import UIKit
import Montage
import SnapKit

// MARK: - SwitchPreview

import SwiftUI
struct SwitchPreview: View {
    @State private var isOn: Bool = false
    @State private var sizeIndex: Int = 0
    @State private var disabled: Bool = false
    
    var body: some View {
        ScrollView {
            VStack(alignment: .leading) {
                Text("Preview").bold()
                Control.Switch($isOn, size: Control.Switch.Size.allCases[sizeIndex]) {
                    print($0)
                }
                .disabled(disabled)
                Text("Options").bold()
                HStack {
                    Text("size")
                    SegmentedControl(selectedIndex: $sizeIndex, labels: Control.Switch.Size.allCases.map(\.rawValue))
                        .size(.small)
                }
                HStack {
                    Text("disabled")
                    Control.Switch($disabled)
                }
            }
            .padding()
        }
        .background(SwiftUI.Color.semantic(.backgroundNormal))
    }
}

#Preview {
    SwitchPreview()
}

